+          throw new TypeException("definition of " + vars[i] + " has type " + rhsType + ", expected " + def.type());
+        }
+      }
+
+      // Type check body
+      return l.body().accept(newVisitor);
+    }
+
+    public Type forBlock(Block b) {
+      AST[] exps = b.exps();
+      int n = exps.length;
+      Type result = null;
+      for (int i = 0; i < n; i++) {
+        result = exps[i].accept(this);
+      }
+      return result;
+    }
